:"445"},"image":{"@id":"https://roadtostudy.com/#logo"}},{"@type":"WebSite","@id":"https://roadtostudy.com/#website","url":"https://roadtostudy.com","name":"Road to Study - Turkey University Guide for Students","alternateName":"Road to Study in Turkey","publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"fr-FR"},{"@type":"ImageObject","@id":"https://roadtostudy.com/wp-content/uploads/2025/05/scientific-event-and-organization-support-in-turkey.webp","url":"https://roadtostudy.com/wp-content/uploads/2025/05/scientific-event-and-organization-support-in-turkey.webp","width":"2336","height":"1760","caption":"Scientific event and organization supports in Turkey","inLanguage":"fr-FR"},{"@type":"WebPage","@id":"https://roadtostudy.com/fr/culture-du-travail-et-relations-professionnelles-en-turquie/#webpage","url":"https://roadtostudy.com/fr/culture-du-travail-et-relations-professionnelles-en-turquie/","name":"Culture du travail et relations professionnelles en Turquie - RoadtoStudy","datePublished":"2026-04-20T07:00:00+03:00","dateModified":"2026-04-20T07:00:00+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"primaryImageOfPage":{"@id":"https://roadtostudy.com/wp-content/uploads/2025/05/scientific-event-and-organization-support-in-turkey.webp"},"inLanguage":"fr-FR"},{"@type":"Person","@id":"https://roadtostudy.com/fr/author/murat/","name":"Murat","url":"https://roadtostudy.com/fr/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"fr-FR"}},{"@type":"BlogPosting","headline":"Culture du travail et relations professionnelles en Turquie - RoadtoStudy","datePublished":"2026-04-20T07:00:00+03:00","dateModified":"2026-04-20T07:00:00+03:00","articleSection":"Adaptation cultu