ostudy.com/#logo"}},{"@type":"WebSite","@id":"https://roadtostudy.com/#website","url":"https://roadtostudy.com","name":"Road to Study - Turkey University Guide for Students","alternateName":"Road to Study in Turkey","publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"fr-FR"},{"@type":"WebPage","@id":"https://roadtostudy.com/fr/structures-salariales-et-processus-de-negociation-en-turquie/#webpage","url":"https://roadtostudy.com/fr/structures-salariales-et-processus-de-negociation-en-turquie/","name":"Structures salariales et processus de négociation en Turquie - RoadtoStudy","datePublished":"2026-04-03T15:00:00+03:00","dateModified":"2026-04-03T15:00:00+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"inLanguage":"fr-FR"},{"@type":"Person","@id":"https://roadtostudy.com/fr/author/murat/","name":"Murat","url":"https://roadtostudy.com/fr/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"fr-FR"}},{"@type":"BlogPosting","headline":"Structures salariales et processus de négociation en Turquie - RoadtoStudy","datePublished":"2026-04-03T15:00:00+03:00","dateModified":"2026-04-03T15:00:00+03:00","articleSection":"Carrière et Stage","author":{"@id":"https://roadtostudy.com/fr/author/murat/","name":"Murat"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"Découvrez les structures salariales et les processus de négociation en Turquie. Informez-vous, connaissez vos droits et progressez dans votre carrière !","name":"Structures salariales et processus de négociation en Turquie - RoadtoStudy","@id":"https://roadtostudy.com/fr/structures-salariales-et-processus-de-negociation-en-turquie/#richSnippet","isPartOf":{"@id":"https://roadtostudy.com/fr/struc