<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-5" dir="auto" data-message-author-role="assistant" data-message-id="99359d96-83d8-4726-8588-5ebfe2203d11" data-message-model-slug="gpt-5-mini">
